import 'dart:convert'; import 'dart:io';
List<String> justify(List<String> words, int maxWidth) { final res = <String>[]; var i = 0; while (i < words.length) { var j = i, total = 0; while (j < words.length && total + words[j].length + (j - i) <= maxWidth) { total += words[j].length; j++; } final gaps = j - i - 1; String line; if (j == words.length || gaps == 0) { line = words.sublist(i, j).join(' '); line += ' ' * (maxWidth - line.length); } else { final spaces = maxWidth - total, base = spaces ~/ gaps, extra = spaces % gaps; final b = StringBuffer(); for (var k = i; k < j - 1; k++) { b.write(words[k]); b.write(' ' * (base + (k - i < extra ? 1 : 0))); } b.write(words[j - 1]); line = b.toString(); } res.add(line); i = j; } return res; }
Future<void> main() async { final lines = const LineSplitter().convert(await stdin.transform(utf8.decoder).join()); if (lines.isNotEmpty) { var idx = 0; final t = int.parse(lines[idx++]); final out = <String>[]; for (var tc = 0; tc < t; tc++) { final n = int.parse(lines[idx++]); final words = lines.sublist(idx, idx + n); idx += n; final width = int.parse(lines[idx++]); final ans = justify(words, width); out.add(ans.length.toString()); for (final s in ans) out.add('|$s|'); if (tc + 1 < t) out.add('='); } stdout.write(out.join('\n')); } }
